'use client';

import { useState } from 'react';
import { motion } from 'framer-motion';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Stars, Float, PerspectiveCamera } from '@react-three/drei';
import { EffectComposer, Bloom } from '@react-three/postprocessing';
import ArcReactor from './3d/ArcReactor';

function Scene() {
  return (
    <>
      <PerspectiveCamera makeDefault position={[0, 0, 8]} fov={50} />
      <OrbitControls
        enableZoom={false}
        enablePan={false}
        maxPolarAngle={Math.PI / 2}
        minPolarAngle={Math.PI / 2}
        rotateSpeed={0.5}
      />

      {/* Lighting */}
      <ambientLight intensity={0.3} />
      <pointLight position={[10, 10, 10]} intensity={2} color="#00D4FF" />
      <pointLight position={[-10, -10, -10]} intensity={1} color="#FF6B9D" />

      {/* Arc Reactor - centerpiece */}
      <Float speed={2} rotationIntensity={0.3} floatIntensity={0.5}>
        <ArcReactor position={[0, 0, 0]} scale={1.5} />
      </Float>

      {/* Background particles */}
      <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />

      {/* Post-processing */}
      <EffectComposer>
        <Bloom luminanceThreshold={0} luminanceSmoothing={0.9} height={300} intensity={2} />
      </EffectComposer>
    </>
  );
}

export default function DesktopHero() {
  const [showModal, setShowModal] = useState(false);

  return (
    <div className="min-h-screen bg-holo-bg relative overflow-hidden">
      {/* Animated background grid */}
      <div className="absolute inset-0 opacity-20">
        <div className="absolute inset-0" style={{
          backgroundImage: `
            linear-gradient(rgba(0, 212, 255, 0.1) 1px, transparent 1px),
            linear-gradient(90deg, rgba(0, 212, 255, 0.1) 1px, transparent 1px)
          `,
          backgroundSize: '50px 50px',
          animation: 'grid-move 20s linear infinite',
        }} />
      </div>

      {/* WebGL Canvas */}
      <div className="absolute inset-0">
        <Canvas dpr={[1, 2]} gl={{ antialias: true, alpha: true }}>
          <Scene />
        </Canvas>
      </div>

      {/* Scanline overlay (CSS) */}
      <div className="absolute inset-0 pointer-events-none" style={{
        background: 'repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(0, 212, 255, 0.03) 2px, rgba(0, 212, 255, 0.03) 4px)',
      }} />

      {/* Vignette effect */}
      <div className="absolute inset-0 pointer-events-none" style={{
        background: 'radial-gradient(circle at center, transparent 0%, rgba(0, 0, 0, 0.4) 100%)',
      }} />

      {/* Content overlay */}
      <div className="relative z-10 container mx-auto px-6 py-12">
        <div className="max-w-4xl mx-auto text-center">
          <motion.h1
            className="text-6xl md:text-7xl font-heading mb-6 text-gradient-holographic"
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 1, delay: 0.2 }}
          >
            Aryan Iyappan
          </motion.h1>

          <motion.p
            className="text-2xl md:text-3xl text-holo-text mb-12"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 1, delay: 0.5 }}
          >
            Technical Founder building AI-powered developer tools
          </motion.p>

          {/* Dual CTAs */}
          <motion.div
            className="flex gap-6 justify-center"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8, delay: 0.8 }}
          >
            <button
              onClick={() => setShowModal(true)}
              className="px-8 py-4 bg-holo-blue-primary text-holo-bg font-heading font-bold rounded-lg hover:bg-holo-blue-secondary transition-all hover:scale-105 hover:shadow-lg hover:shadow-holo-blue-primary/50"
            >
              Quick Pitch
            </button>
            <button
              onClick={() => (window.location.href = '#projects')}
              className="px-8 py-4 border-2 border-holo-blue-primary text-holo-blue-primary font-heading font-bold rounded-lg hover:bg-holo-blue-primary/10 transition-all hover:scale-105"
            >
              Deep Dive
            </button>
          </motion.div>
        </div>
      </div>

      {/* Quick Pitch Modal */}
      {showModal && (
        <motion.div
          className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-6"
          onClick={() => setShowModal(false)}
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
        >
          <motion.div
            className="bg-holo-bg/95 backdrop-blur-xl border border-holo-blue-primary/50 rounded-lg max-w-2xl w-full p-8"
            onClick={(e) => e.stopPropagation()}
            initial={{ scale: 0.9, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            transition={{ duration: 0.3 }}
          >
            <h2 className="text-3xl font-heading mb-4 text-gradient-holographic">What I&apos;m Building</h2>

            <div className="space-y-4 text-holo-text">
              <p className="text-lg">
                I&apos;m building AI-powered developer tools that 10x engineering velocity.
              </p>

              <div className="grid grid-cols-2 gap-4 my-6">
                <div className="border border-holo-coral/50 rounded-lg p-4 bg-holo-coral/5">
                  <div className="text-holo-coral font-mono text-sm mb-1">Open Source</div>
                  <div className="text-2xl font-heading">500+</div>
                  <div className="text-sm text-gray-400">GitHub stars</div>
                </div>

                <div className="border border-holo-teal/50 rounded-lg p-4 bg-holo-teal/5">
                  <div className="text-holo-teal font-mono text-sm mb-1">Experience</div>
                  <div className="text-2xl font-heading">5 years</div>
                  <div className="text-sm text-gray-400">Full-stack dev</div>
                </div>
              </div>

              <p className="text-sm text-gray-400">
                Ship production code at VC-startup speed. Deep expertise in GraphQL,
                FastAPI, and modern React.
              </p>
            </div>

            <button
              onClick={() => {
                setShowModal(false);
                window.location.href = '#projects';
              }}
              className="mt-6 w-full px-6 py-3 bg-gradient-playful text-white font-heading font-bold rounded-lg hover:opacity-90 transition-opacity hover:scale-105"
            >
              Want more detail?
            </button>
          </motion.div>
        </motion.div>
      )}

      <style jsx>{`
        @keyframes grid-move {
          0% { background-position: 0 0; }
          100% { background-position: 50px 50px; }
        }
      `}</style>
    </div>
  );
}

