import { useEffect, useState } from 'react';
import ArcReactor from './3d/ArcReactor';

export default function Scene() {
  const [Canvas, setCanvas] = useState<any>(null);
  const [OrbitControls, setOrbitControls] = useState<any>(null);
  const [Stars, setStars] = useState<any>(null);
  const [Float, setFloat] = useState<any>(null);
  const [PerspectiveCamera, setPerspectiveCamera] = useState<any>(null);
  const [EffectComposer, setEffectComposer] = useState<any>(null);
  const [Bloom, setBloom] = useState<any>(null);
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    Promise.all([
      import('@react-three/fiber'),
      import('@react-three/drei'),
      import('@react-three/postprocessing'),
    ]).then(([fiber, drei, postprocessing]) => {
      setCanvas(() => fiber.Canvas);
      setOrbitControls(() => drei.OrbitControls);
      setStars(() => driei.Stars);
      setFloat(() => drei.Float);
      setPerspectiveCamera(() => drei.PerspectiveCamera);
      setEffectComposer(() => postprocessing.EffectComposer);
      setBloom(() => postprocessing.Bloom);
      setLoaded(true);
    });
  }, []);

  if (!loaded || !Canvas) {
    return (
      <div style={{ width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <div style={{ color: '#00D4FF', fontSize: '18px' }}>Loading 3D scene...</div>
      </div>
    );
  }

  function InnerScene() {
    return (
      <>
        <PerspectiveCamera makeDefault position={[0, 0, 8]} fov={50} />
        <OrbitControls
          enableZoom={false}
          enablePan={false}
          maxPolarAngle={Math.PI / 2}
          minPolarAngle={Math.PI / 2}
          rotateSpeed={0.5}
        />

        {/* Lighting */}
        <ambientLight intensity={0.3} />
        <pointLight position={[10, 10, 10]} intensity={2} color="#00D4FF" />
        <pointLight position={[-10, -10, -10]} intensity={1} color="#FF6B9D" />

        {/* Arc Reactor - centerpiece */}
        <Float speed={2} rotationIntensity={0.3} floatIntensity={0.5}>
          <ArcReactor position={[0, 0, 0]} scale={1.5} />
        </Float>

        {/* Background particles */}
        <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />

        {/* Post-processing */}
        <EffectComposer>
          <Bloom luminanceThreshold={0} luminanceSmoothing={0.9} height={300} intensity={2} />
        </EffectComposer>
      </>
    );
  }

  return (
    <div style={{ width: '100%', height: '100%', position: 'absolute', top: 0, left: 0 }}>
      <Canvas
        dpr={[1, 2]}
        gl={{ antialias: true, alpha: true }}
        style={{ width: '100%', height: '100%' }}
      >
        <InnerScene />
      </Canvas>
    </div>
  );
}

