'use client';

import { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';

interface ArcReactorProps {
  position?: [number, number, number];
  scale?: number;
}

export default function ArcReactor({ position = [0, 0, 0], scale = 1 }: ArcReactorProps) {
  const groupRef = useRef<THREE.Group>(null);
  const coreRef = useRef<THREE.Mesh>(null);
  const ringsRef = useRef<THREE.Group>(null);

  // Create holographic shader material
  const holographicMaterial = useMemo(() => {
    return new THREE.ShaderMaterial({
      uniforms: {
        uTime: { value: 0 },
        uColor1: { value: new THREE.Color('#00D4FF') },
        uColor2: { value: new THREE.Color('#00F5D4') },
      },
      vertexShader: `
        varying vec2 vUv;
        varying vec3 vNormal;
        uniform float uTime;

        void main() {
          vUv = uv;
          vNormal = normal;

          vec3 pos = position;
          // Add subtle pulsing
          float pulse = sin(uTime * 2.0) * 0.02;
          pos += normal * pulse;

          gl_Position = projectionMatrix * modelViewMatrix * vec4(pos, 1.0);
        }
      `,
      fragmentShader: `
        uniform float uTime;
        uniform vec3 uColor1;
        uniform vec3 uColor2;
        varying vec2 vUv;
        varying vec3 vNormal;

        void main() {
          // Holographic scanlines
          float scanline = sin(vUv.y * 50.0 + uTime * 3.0) * 0.1;

          // Fresnel glow effect
          vec3 viewDir = normalize(cameraPosition - vNormal);
          float fresnel = pow(1.0 - dot(viewDir, vNormal), 2.0);

          // Color mix
          vec3 color = mix(uColor1, uColor2, sin(uTime) * 0.5 + 0.5);

          // Combine effects
          float alpha = 0.6 + fresnel * 0.4 + scanline;

          gl_FragColor = vec4(color, alpha);
        }
      `,
      transparent: true,
      side: THREE.DoubleSide,
      depthWrite: false,
      blending: THREE.AdditiveBlending,
    });
  }, []);

  useFrame(({ clock }) => {
    const elapsedTime = clock.getElapsedTime();

    // Update shader uniforms
    if (holographicMaterial.uniforms) {
      holographicMaterial.uniforms.uTime.value = elapsedTime;
    }

    // Rotate rings
    if (ringsRef.current) {
      ringsRef.current.rotation.x = elapsedTime * 0.3;
      ringsRef.current.rotation.y = elapsedTime * 0.5;
    }

    // Pulse core
    if (coreRef.current) {
      const pulse = 1 + Math.sin(elapsedTime * 2) * 0.1;
      coreRef.current.scale.setScalar(pulse);
    }

    // Slow rotation of entire reactor
    if (groupRef.current) {
      groupRef.current.rotation.y = elapsedTime * 0.2;
    }
  });

  return (
    <group ref={groupRef} position={position} scale={scale}>
      {/* Core sphere */}
      <mesh ref={coreRef}>
        <sphereGeometry args={[0.8, 32, 32]} />
        <meshBasicMaterial
          color="#00D4FF"
          transparent
          opacity={0.9}
          blending={THREE.AdditiveBlending}
        />
        <pointLight color="#00D4FF" intensity={5} distance={20} />
      </mesh>

      {/* Rotating rings */}
      <group ref={ringsRef}>
        {/* Inner ring */}
        <mesh rotation={[Math.PI / 2, 0, 0]}>
          <torusGeometry args={[1.2, 0.05, 16, 100]} />
          <primitive object={holographicMaterial} attach="material" />
        </mesh>

        {/* Middle ring */}
        <mesh rotation={[0, Math.PI / 2, 0]}>
          <torusGeometry args={[1.5, 0.08, 16, 100]} />
          <primitive object={holographicMaterial.clone()} attach="material" />
        </mesh>

        {/* Outer ring */}
        <mesh rotation={[Math.PI / 4, Math.PI / 4, 0]}>
          <torusGeometry args={[1.8, 0.1, 16, 100]} />
          <primitive object={holographicMaterial.clone()} attach="material" />
        </mesh>
      </group>

      {/* Orbiting particles */}
      {[...Array(8)].map((_, i) => {
        const angle = (i / 8) * Math.PI * 2;
        const radius = 2.2;
        return (
          <mesh key={i} position={[Math.cos(angle) * radius, 0, Math.sin(angle) * radius]}>
            <sphereGeometry args={[0.05, 8, 8]} />
            <meshBasicMaterial
              color="#00F5D4"
              transparent
              opacity={0.8}
              blending={THREE.AdditiveBlending}
            />
          </mesh>
        );
      })}

      {/* Outer glow shell */}
      <mesh scale={[2.5, 2.5, 2.5]}>
        <sphereGeometry args={[1, 32, 32]} />
        <meshBasicMaterial
          color="#00D4FF"
          transparent
          opacity={0.05}
          blending={THREE.AdditiveBlending}
          side={THREE.BackSide}
        />
      </mesh>
    </group>
  );
}

